module top_module(clk, en, in, out) ;parameter n = 16;  
  input clk, en ;
  input  [n-1:0] in ;
  output [n-1:0] out ;
  reg    [n-1:0] out ;
  wire   [n-1:0] next_out ;

  wire inv_next_out = en ? in : out;
  assign next_out = inv_next_out;

  always @(posedge clk)
    out = next_out;endmodule
